boolean phonesIssue = false;
boolean tokensIssue = false;

if (duoPhones != null && !duoPhones.isEmpty()) {

   List phones = getDuoUserObject(duoUsername, "phones");

   if (phones != null && !phones.isEmpty()) {

     phonesIssue = true;

   }

}

if (duoTokens != null && !duoTokens.isEmpty()) {

   List tokens = getDuoUserObject(duoUsername, "tokens");

   if (tokens != null && !tokens.isEmpty()) {

     tokensIssue = true;

   }

}

if (phonesIssue && tokensIssue) {

throw new GeneralException("Tokens and Phones appear to remain following DELETE attempt against [" + duoUsername + "]; if this occurred during an Immediate Termination inform the Security Team immediately; otherwise, simply mark this WorkItem complete.");

} else if (phonesIssue) {

throw new GeneralException("Phones appear to remain following DELETE attempt against [" + duoUsername + "]; if this occurred during an Immediate Termination inform the Security Team immediately; otherwise, simply mark this WorkItem complete.");

} else if (tokensIssue) {

throw new GeneralException("Tokens appear to remain following DELETE attempt against [" + duoUsername + "]; if this occurred during an Immediate Termination inform the Security Team immediately; otherwise, simply mark this WorkItem complete.");

}
